// --- types.d.ts ---
import { ReactNode } from 'react';

export interface ForecastItem {
  day: string;
  icon: string;
  high: number;
  low: number;
}

export interface Props {
  city: string;
  temperature: number;
  condition: string;
  humidity: number;
  windSpeed: number;
  unit?: string;
  forecast: ForecastItem[];
}

export interface ForecastDayProps {
  item: ForecastItem;
  unit: string;
}

export interface HookReturn {
  formattedTemp: string;
  formattedWind: string;
  formattedHumidity: string;
  unitLabel: string;
  forecast: ForecastItem[];
}


// --- constants.ts ---
// constants.ts — static data, mappings, configurations

export const DEFAULT_UNIT = 'C';

export const UNIT_LABELS: Record<string, string> = {
  C: '°C',
  F: '°F',
};

export const WIND_SPEED_UNITS: Record<string, string> = {
  C: 'km/h',
  F: 'mph',
};

export const CONDITION_METADATA: Record<string, { color: string; bgGradient: string }> = {
  Clear: {
    color: 'text-yellow-500',
    bgGradient: 'from-blue-400 to-blue-600',
  },
  Cloudy: {
    color: 'text-gray-400',
    bgGradient: 'from-gray-400 to-gray-600',
  },
  Rainy: {
    color: 'text-blue-500',
    bgGradient: 'from-blue-600 to-indigo-800',
  },
  Snowy: {
    color: 'text-blue-200',
    bgGradient: 'from-blue-100 to-blue-300',
  },
  Stormy: {
    color: 'text-purple-600',
    bgGradient: 'from-purple-700 to-slate-900',
  },
  Default: {
    color: 'text-gray-500',
    bgGradient: 'from-sky-400 to-blue-500',
  },
};


// --- hooks.ts ---
// hooks.ts — state, handlers, data transformations
import type { Props, HookReturn } from './types';

export function useComponent(props: Props): HookReturn {
  const { temperature, humidity, windSpeed, unit = 'C', forecast } = props;

  const currentUnit = unit || 'C';
  const unitLabel = `°${currentUnit}`;
  const formattedTemp = `${temperature}${unitLabel}`;
  const formattedWind = `${windSpeed} km/h`;
  const formattedHumidity = `${humidity}%`;

  return {
    formattedTemp,
    formattedWind,
    formattedHumidity,
    unitLabel,
    forecast: forecast || [],
  };
}


// --- ForecastDay.tsx ---
// ForecastDay.tsx — reusable sub-component
import React from 'react';
import { Stack, Text } from '@ggui-ai/design/primitives';
import type { ForecastDayProps } from './types';

export function ForecastDay({ item, unit }: ForecastDayProps) {
  return (
    <Stack direction="vertical" align="center" gap={4}>
      <Text variant="label" weight="semibold">
        {item.day}
      </Text>

      <Text size="2xl" aria-hidden="true">
        {item.icon}
      </Text>

      <Stack direction="horizontal" gap={4} align="center">
        <Text size="sm" weight="medium">
          {item.high}°
        </Text>
        <Text 
          size="sm" 
          color="var(--ggui-color-neutral-500, #6b7280)"
        >
          {item.low}°
        </Text>
      </Stack>
    </Stack>
  );
}


// --- ui.tsx ---
import React from 'react';
import { Container, Stack, Heading, Text, Card, Divider } from '@ggui-ai/design/primitives';
import type { Props, HookReturn } from './types';
import { ForecastDay } from './components';

export function ComponentUI(props: Props & HookReturn) {
  const {
    city,
    condition,
    forecast,
    formattedTemp,
    formattedWind,
    formattedHumidity,
    unit = 'C',
  } = props;

  return (
    <Container maxWidth="sm" padding={24} center>
      <Card shadow="md" padding={24} radius="xl" border>
        <Stack gap={24}>
          {/* Header Section */}
          <Stack align="center">
            <Heading level={1} align="center">
              {city}
            </Heading>
          </Stack>

          {/* Main Temperature Section */}
          <Stack align="center" gap={8}>
            <Text
              size="4xl"
              weight="bold"
              color="var(--ggui-color-primary-600, #0284c7)"
            >
              {formattedTemp}
            </Text>
            <Text variant="bodyLarge" weight="medium" color="var(--ggui-color-neutral-700, #374151)">
              {condition}
            </Text>
          </Stack>

          {/* Details Section (Humidity & Wind) */}
          <Stack direction="horizontal" justify="around" align="center" gap={16}>
            <Stack align="center" gap={4}>
              <Text variant="label" color="var(--ggui-color-neutral-500, #6b7280)">
                Humidity
              </Text>
              <Text weight="semibold">{formattedHumidity}</Text>
            </Stack>
            <Divider orientation="vertical" margin={12} />
            <Stack align="center" gap={4}>
              <Text variant="label" color="var(--ggui-color-neutral-500, #6b7280)">
                Wind
              </Text>
              <Text weight="semibold">{formattedWind}</Text>
            </Stack>
          </Stack>

          <Divider margin={8} />

          {/* Forecast Strip Section */}
          <Stack direction="horizontal" gap={12} justify="between" wrap>
            {forecast.map((item, index) => (
              <ForecastDay 
                key={`${item.day}-${index}`} 
                item={item} 
                unit={unit} 
              />
            ))}
          </Stack>
        </Stack>
      </Card>
    </Container>
  );
}


// --- render.tsx ---
// render.tsx — entry point
import React from 'react';
import type { Props } from './types';
import { useComponent } from './hooks';
import { ComponentUI } from './ui';

export default function Component(props: Props) {
  const state = useComponent(props);
  return <ComponentUI {...props} {...state} />;
}
